#include<bits/stdc++.h>
using namespace std;
long long a[100010],b[100010];
int main()
{
    long long n;
    scanf("%lld",&n);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
        b[i]=a[i]-a[i-1];
    }
    long long cnt1=0,cnt2=0;
    for(long long i=2;i<=n;i++)
    {
        if(b[i]<0)
        {
            cnt2-=b[i];
        }
        else
        {
            cnt1+=b[i];
        }
    }
    printf("%lld\n%lld",max(cnt1,cnt2),abs(cnt1-cnt2)+1);
    return 0;
}
